Lastly, override `NativeOnMouseMove` method to implement the drag detection based on the distance moved:

```cpp
FReply USkillBarSlotUI::NativeOnMouseMove(const FGeometry& InGeometry, const FPointerEvent& InMouseEvent)
{
    FReply CurrentReply = Super::NativeOnMouseMove(InGeometry, InMouseEvent);

    if (InMouseEvent.IsMouseButtonDown(FKey(EKeys::LeftMouseButton)))
    {
        if (AbilityLevel != 0 && AbilityIcon)
        {
            FVector2D CurrentMousePosition = InMouseEvent.GetScreenSpacePosition();
            float DistanceMoved = FVector2D::Distance(InitialMousePosition, CurrentMousePosition);

            if (DistanceMoved > FSlateApplication::Get().GetDragTriggerDistnace()) // Use the UE drag distance threshold
            {
                // Start the drag operation
                return CurrentReply.DetectDrag(TakeWidget(), EKeys::LeftMouseButton);
            }
            else
            {
                // Still waiting for the distance threshold to be exceeded
                return CurrentReply.Handled();
            }
        }
    }

    return CurrentReply;
}
```

Using this approach, the drag detection will only be initiated if the user moves the mouse beyond the threshold distance, and it won't consume the left mouse button press when the drag operation starts.

