FReply UMyDraggableWidget::NativeOnMouseButtonDown(const FGeometry& InGeometry, const FPointerEvent& InMouseEvent)
{
    FReply CurrentReply = Super::NativeOnMouseButtonDown(InGeometry, InMouseEvent);

    if (InMouseEvent.GetEffectingButton() == EKeys::LeftMouseButton)
    {
        InitialMousePosition = InMouseEvent.GetScreenSpacePosition();
        bIsDetectingDrag = true;
        return CurrentReply.CaptureMouse(SharedThis(this));
    }

    return CurrentReply;
}

FReply UMyDraggableWidget::NativeOnMouseButtonUp(const FGeometry& InGeometry, const FPointerEvent& InMouseEvent)
{
    FReply CurrentReply = Super::NativeOnMouseButtonUp(InGeometry, InMouseEvent);

    if (InMouseEvent.GetEffectingButton() == EKeys::LeftMouseButton && HasMouseCapture())
    {
        if (bIsDetectingDrag)
        {
            InitialMousePosition = FVector2D::ZeroVector;
            bIsDetectingDrag = false;
        }

        return CurrentReply.ReleaseMouseCapture();
    }

    return CurrentReply;
}
```

By calling `CaptureMouse` on the FReply in `NativeOnMouseButtonDown`, the widget will capture all subsequent mouse events until the mouse button is released. Then, you can call `ReleaseMouseCapture` in `NativeOnMouseButtonUp` when the left mouse button is released, ensuring your widget will handle this event effectively.

This change should resolve the issue you're having with `NativeOnMouseButtonUp`. If you still experience difficulties, it's worth checking if there are other widgets or elements in your UI that interfere with your draggable widget's behavior, possibly due to their Z-order, overlapping boundaries, or visibility settings.

